class Solution {
    public boolean isValid(String s) {
        java.util.ArrayDeque<Character> st = new java.util.ArrayDeque<>();
        for (char c : s.toCharArray()) {
            if (c == '(' || c == '[' || c == '{') st.push(c);
            else {
                if (st.isEmpty()) return false;
                char o = st.pop();
                if (c == ')' && o != '(') return false;
                if (c == ']' && o != '[') return false;
                if (c == '}' && o != '{') return false;
            }
        }
        return st.isEmpty();
    }
}

