class Solution {
    public String decodeString(String s) {
        java.util.ArrayDeque<Integer> counts = new java.util.ArrayDeque<>();
        java.util.ArrayDeque<StringBuilder> strs = new java.util.ArrayDeque<>();
        StringBuilder cur = new StringBuilder();
        int k = 0;
        for (char c : s.toCharArray()) {
            if (Character.isDigit(c)) k = k * 10 + (c - '0');
            else if (c == '[') {
                counts.push(k);
                strs.push(cur);
                cur = new StringBuilder();
                k = 0;
            } else if (c == ']') {
                StringBuilder prev = strs.pop();
                int n = counts.pop();
                for (int i = 0; i < n; i++) prev.append(cur);
                cur = prev;
            } else cur.append(c);
        }
        return cur.toString();
    }
}

solution.python:
class Solution:
    def decodeString(self, s: str) -> str:
        counts, strs = [], []
        cur, k = [], 0
        for c in s:
            if c.isdigit():
                k = k * 10 + int(c)
            elif c == '[':
                counts.append(k)
                strs.append(cur)
                cur, k = [], 0
            elif c == ']':
                prev = strs.pop()
                prev.extend(cur * counts.pop())
                cur = prev
            else:
                cur.append(c)
        return ''.join(cur)

