class Solution:
    def calculate(self, s: str) -> int:
        st = []
        num, op = 0, '+'
        for i, c in enumerate(s):
            if c.isdigit():
                num = num * 10 + int(c)
            if (not c.isdigit() and c != ' ') or i == len(s) - 1:
                if op == '+':
                    st.append(num)
                elif op == '-':
                    st.append(-num)
                elif op == '*':
                    st.append(st.pop() * num)
                else:
                    prev = st.pop()
                    st.append(int(prev / num))  # toward zero
                op, num = c, 0
        return sum(st)
